import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.Iterator;
import java.util.Map;

public class JsonTreeReaderTest {

  private JsonTreeReader reader;

  @BeforeEach
  public void setUp() throws Exception {
    // Create a dummy JsonElement for constructor (using JsonNull)
    reader = new JsonTreeReader(com.google.gson.JsonNull.INSTANCE);
  }

  @Test
  public void testPromoteNameToValue_success() throws Exception {
    // Arrange
    // Mock an Iterator<Map.Entry<?, ?>> with one entry
    @SuppressWarnings("unchecked")
    Iterator<Map.Entry<Object, Object>> mockIterator = mock(Iterator.class);
    @SuppressWarnings("unchecked")
    Map.Entry<Object, Object> mockEntry = mock(Map.Entry.class);

    when(mockEntry.getKey()).thenReturn("mockKey");
    when(mockEntry.getValue()).thenReturn(new JsonPrimitive("mockValue"));
    when(mockIterator.next()).thenReturn(mockEntry);

    // Use reflection to set the private stack field with the mockIterator at top
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = (Object[]) stackField.get(reader);
    stack[0] = mockIterator;

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(reader, 1);

    // Spy on reader
    JsonTreeReader spyReader = spy(reader);

    // Stub private expect method via reflection using doAnswer on spyReader's method via reflection
    Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
    expectMethod.setAccessible(true);

    // Use doAnswer with reflection on spyReader's expect method
    doAnswer(invocation -> null).when(spyReader).expect(JsonToken.NAME);
    // Above line causes compile error because expect is private.
    // Instead, use doAnswer on spyReader with reflection invoke using Mockito's doAnswer with doCallRealMethod workaround:

    // Remove the above doAnswer line and replace with below:
    // Since expect is private, we cannot mock it directly with Mockito.
    // Instead, override the method via spy and reflection:
    // Use Mockito's doAnswer on a method wrapper:

    // Create a wrapper method in spyReader to call expect via reflection
    // But we cannot add methods to spyReader here.
    // Alternative: Use Mockito's doAnswer on spyReader's promoteNameToValue method to skip expect call.
    // But we want to test promoteNameToValue fully.

    // So instead, use a helper to replace expect method via reflection:
    // Use a subclass that overrides expect to do nothing.

    // Implement a subclass of JsonTreeReader that overrides expect to do nothing:
    JsonTreeReader testReader = new JsonTreeReader(com.google.gson.JsonNull.INSTANCE) {
      @Override
      protected void expect(JsonToken expected) {
        // do nothing
      }
    };

    // Set stack and stackSize on testReader
    stackField.set(testReader, stack);
    stackSizeField.setInt(testReader, 1);

    JsonTreeReader spyTestReader = spy(testReader);

    // Act
    Method promoteNameToValue = JsonTreeReader.class.getDeclaredMethod("promoteNameToValue");
    promoteNameToValue.setAccessible(true);
    promoteNameToValue.invoke(spyTestReader);

    // Assert
    int stackSizeAfter = stackSizeField.getInt(spyTestReader);
    assertEquals(3, stackSizeAfter);

    Object[] stackAfter = (Object[]) stackField.get(spyTestReader);

    Object top = stackAfter[stackSizeAfter - 1];
    assertTrue(top instanceof JsonPrimitive);
    assertEquals("mockKey", ((JsonPrimitive) top).getAsString());

    Object second = stackAfter[stackSizeAfter - 2];
    assertTrue(second instanceof JsonPrimitive);
    assertEquals("mockValue", ((JsonPrimitive) second).getAsString());

    assertSame(mockIterator, stackAfter[0]);

    verify(mockIterator).next();
  }

  @Test
  public void testPromoteNameToValue_expectThrows() throws Exception {
    // Create subclass that overrides expect to throw IOException
    JsonTreeReader testReader = new JsonTreeReader(com.google.gson.JsonNull.INSTANCE) {
      @Override
      protected void expect(JsonToken expected) throws IOException {
        throw new IOException("Expected token not found");
      }
    };

    Method promoteNameToValue = JsonTreeReader.class.getDeclaredMethod("promoteNameToValue");
    promoteNameToValue.setAccessible(true);

    IOException thrown = assertThrows(IOException.class, () -> promoteNameToValue.invoke(testReader));
    assertTrue(thrown.getCause().getMessage().contains("Expected token not found"));
  }
}
